import{_ as e,o as r,c as t,a1 as l}from"./chunks/framework.BwbI10pK.js";const _=JSON.parse('{"title":"职业体系","description":"","frontmatter":{},"headers":[],"relativePath":"career/index.md","filePath":"career/index.md"}'),i={name:"career/index.md"};function o(n,a,s,c,h,d){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="职业体系" tabindex="-1">职业体系 <a class="header-anchor" href="#职业体系" aria-label="Permalink to &quot;职业体系&quot;">​</a></h1><blockquote><p>副标题：从能力模型到技术影响力，构建可量化的成长路径而非空泛建议</p></blockquote><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>前端工程师的成长不是&quot;多写几年代码就能自动升级&quot;，而是需要主动构建能力模型、规划技术路径、积累技术影响力。本模块不提供&quot;多读源码、多刷题&quot;这类空泛建议，而是拆解为可量化的能力维度、可执行的成长阶梯、可观察的影响力信号。</p><p>无论是刚入行的初级工程师，还是希望突破到架构师的中高级工程师，都能在本模块找到对应的进阶框架。</p><h2 id="核心主题" tabindex="-1">核心主题 <a class="header-anchor" href="#核心主题" aria-label="Permalink to &quot;核心主题&quot;">​</a></h2><ul><li><strong>能力模型</strong>：T 型 vs π 型人才、技术深度与广度的量化维度、能力雷达图</li><li><strong>成长路径</strong>：初级 → 中级 → 高级 → 资深 → 架构师的关键跃迁点与瓶颈</li><li><strong>技术影响力</strong>：代码贡献、技术分享、开源参与、技术决策、团队赋能的层层递进</li><li><strong>职业决策</strong>：技术线 vs 管理线、大厂 vs 创业公司、跳槽节奏与时机判断</li></ul><h2 id="文章导览" tabindex="-1">文章导览 <a class="header-anchor" href="#文章导览" aria-label="Permalink to &quot;文章导览&quot;">​</a></h2><ul><li><a href="/career/capability-model">前端工程师能力模型：从 T 型到 π 型人才的进阶框架</a> — 量化能力维度，避免&quot;感觉自己什么都会一点&quot;</li><li><a href="/career/growth-path">技术成长路径：从初级到架构师的能力跃迁</a> — 每一级别的关键能力、典型瓶颈与突破方法</li><li><a href="/career/technical-influence">技术影响力构建：从代码贡献到技术领导力</a> — 影响力的五个层级与可观察的信号</li></ul><h2 id="适用读者" tabindex="-1">适用读者 <a class="header-anchor" href="#适用读者" aria-label="Permalink to &quot;适用读者&quot;">​</a></h2><ul><li>初中级前端工程师，希望明确下一阶段的成长方向</li><li>高级 / 资深工程师，希望突破到架构师或技术负责人</li><li>技术管理者，需要建立团队的能力评估与培养体系</li></ul>',11)])])}const p=e(i,[["render",o]]);export{_ as __pageData,p as default};
